import{c as t,Q as o,j as i,m as a}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Public Assets Directory","description":"","frontmatter":{},"headers":[],"relativePath":"public/README.md","filePath":"public/README.md"}'),r={name:"public/README.md"};function s(c,e,d,l,n,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="public-assets-directory" tabindex="-1">Public Assets Directory <a class="header-anchor" href="#public-assets-directory" aria-label="Permalink to &quot;Public Assets Directory&quot;">​</a></h1><p>This folder serves as the central repository for all static media assets used on Jian Lai Wiki.</p><h2 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h2><ul><li><code>images/banners/</code> - Horizontal images used in <code>&lt;MediaBanner&gt;</code> components at the top of section pages.</li><li><code>images/characters/</code> - Character portraits and key visuals used in <code>&lt;CharacterInfobox&gt;</code> and <code>&lt;ImageFrame&gt;</code>.</li><li><code>images/locations/</code> - Scenery, concept art, and maps.</li><li><code>images/logos/</code> - Site logos, seals, and branding elements.</li><li><code>images/textures/</code> - Subtle paper, ink, or noise overlays (if image-based textures are needed).</li><li><code>videos/</code> - Local <code>.mp4</code> or <code>.webm</code> files used in <code>&lt;HeroMedia&gt;</code> or <code>&lt;VideoEmbed&gt;</code>.</li></ul><h2 id="important-guidelines" tabindex="-1">Important Guidelines <a class="header-anchor" href="#important-guidelines" aria-label="Permalink to &quot;Important Guidelines&quot;">​</a></h2><ol><li><strong>Copyright</strong>: Do not upload copyrighted images from the donghua, manhua, or official artwork without permission or proper attribution.</li><li><strong>Optimization</strong>: Optimize all images (WebP/JPEG) and videos before adding them to keep the wiki lightweight.</li><li><strong>Usage</strong>: Reference these files in markdown or components starting with a forward slash: <code>/images/characters/chen-pingan.jpg</code> (VitePress resolves <code>/</code> to the <code>public/</code> directory).</li></ol>',6)])])}const g=t(r,[["render",s]]);export{m as __pageData,g as default};
